"use strict";(self.webpackChunkauctions_for_woocommerce_doc=self.webpackChunkauctions_for_woocommerce_doc||[]).push([[9295],{7878(t,e,r){r.r(e),r.d(e,{comp:()=>o,data:()=>i});var a=r(641);const s={},o=(0,r(6262).A)(s,[["render",function(t,e){return(0,a.uX)(),(0,a.CE)("div",null,[...e[0]||(e[0]=[(0,a.Fv)('<h1 id="disputes" tabindex="-1"><a class="header-anchor" href="#disputes"><span>Disputes</span></a></h1><p><strong>Auctions → Disputes</strong> — <code>?page=wkafw-disputes</code></p><p>Buyer-raised disputes against auction wins. Track them through resolution; export as CSV for legal / customer support handoff.</p><p><img src="/auctions-for-woocommerce/images/screenshots/admin-disputes.png" alt="Disputes — buyer-raised cases with status, opened-on date, evidence and admin notes"></p><h2 id="what-a-dispute-is" tabindex="-1"><a class="header-anchor" href="#what-a-dispute-is"><span>What a dispute is</span></a></h2><p>A row in <code>wkafw_disputes</code> (<a href="/database.html#table-prefixwkafw_disputes" target="_blank" rel="noopener noreferrer">schema</a>) — created when a customer flags a problem with a won auction (item not received, item not as described, refund request, etc.).</p><table><thead><tr><th>Field</th><th>Source</th></tr></thead><tbody><tr><td><code>auction_id</code></td><td>The disputed auction</td></tr><tr><td><code>user_id</code></td><td>The buyer raising the dispute</td></tr><tr><td><code>reason</code></td><td>Free-text customer-supplied reason</td></tr><tr><td><code>status</code></td><td>open / investigating / resolved / closed</td></tr><tr><td><code>resolution</code></td><td>Admin&#39;s resolution note</td></tr><tr><td><code>created_at</code> / <code>updated_at</code></td><td>timestamps</td></tr></tbody></table><h2 id="how-disputes-are-filed" tabindex="-1"><a class="header-anchor" href="#how-disputes-are-filed"><span>How disputes are filed</span></a></h2><p>A buyer files a dispute from one of three places:</p><table><thead><tr><th>Surface</th><th>How</th></tr></thead><tbody><tr><td>Order page (storefront)</td><td>&quot;Dispute this order&quot; link on completed auction orders</td></tr><tr><td>My Auctions tab</td><td>&quot;Report problem&quot; button on Won tab</td></tr><tr><td>Direct URL</td><td><code>/my-account/dispute/{order_id}/</code> (form)</td></tr></tbody></table><p>Filing rules:</p><ul><li>Must be the auction winner</li><li>Order must be in <code>completed</code> or <code>processing</code> state</li><li>Within <code>wkafw_dispute_window</code> days (default 30)</li></ul><h2 id="page-layout" tabindex="-1"><a class="header-anchor" href="#page-layout"><span>Page layout</span></a></h2><table><thead><tr><th>Section</th><th>Purpose</th></tr></thead><tbody><tr><td>Status filter chips</td><td>Open / Investigating / Resolved / Closed (with counts)</td></tr><tr><td>Search</td><td>by auction ID, buyer email, order ID</td></tr><tr><td>Table</td><td>all disputes, paginated</td></tr><tr><td>Per-row drawer</td><td>full reason + resolution editor</td></tr></tbody></table><h2 id="status-workflow" tabindex="-1"><a class="header-anchor" href="#status-workflow"><span>Status workflow</span></a></h2><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">open  →  investigating  →  resolved</span>\n<span class="line">                              ↓</span>\n<span class="line">                            closed</span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><table><thead><tr><th>Status</th><th>Meaning</th></tr></thead><tbody><tr><td><strong>Open</strong></td><td>Just filed, no admin action yet</td></tr><tr><td><strong>Investigating</strong></td><td>Admin acknowledged, contacting parties</td></tr><tr><td><strong>Resolved</strong></td><td>Outcome decided (refund / ship-replacement / no-action)</td></tr><tr><td><strong>Closed</strong></td><td>All actions taken, dispute archived</td></tr></tbody></table><h2 id="resolution-actions" tabindex="-1"><a class="header-anchor" href="#resolution-actions"><span>Resolution actions</span></a></h2><p>When resolving a dispute, admin picks one or more:</p><table><thead><tr><th>Action</th><th>Effect</th></tr></thead><tbody><tr><td><strong>Full refund</strong></td><td>Refund the order via WC; credit wallet if wallet-paid</td></tr><tr><td><strong>Partial refund</strong></td><td>Custom amount; writes a partial WC refund</td></tr><tr><td><strong>Replacement shipped</strong></td><td>No money moves; status closes when buyer confirms</td></tr><tr><td><strong>No action</strong></td><td>Dispute denied; close with note</td></tr><tr><td><strong>Block buyer</strong></td><td>Add to <a href="/admin-users.html" target="_blank" rel="noopener noreferrer">Blocked Users</a></td></tr><tr><td><strong>Block seller</strong></td><td>Suspend seller / freeze auctions</td></tr></tbody></table><p>The resolution note becomes part of the dispute record and is emailed to the buyer.</p><h2 id="per-row-drawer" tabindex="-1"><a class="header-anchor" href="#per-row-drawer"><span>Per-row drawer</span></a></h2><p>Click a dispute row to expand:</p><ul><li><strong>Full conversation</strong> — buyer&#39;s reason, admin notes (private + buyer-visible)</li><li><strong>Order context</strong> — items, total, payment method, shipping</li><li><strong>Bid trail</strong> — every bid on the auction (cross-reference for fraud)</li><li><strong>Buyer&#39;s history</strong> — past disputes, total spend</li><li><strong>Seller&#39;s history</strong> — past disputes against this seller</li></ul><h2 id="bulk-actions" tabindex="-1"><a class="header-anchor" href="#bulk-actions"><span>Bulk actions</span></a></h2><table><thead><tr><th>Action</th><th>Effect</th></tr></thead><tbody><tr><td><strong>Mark investigating</strong></td><td>Bulk-acknowledge new disputes</td></tr><tr><td><strong>Close all resolved</strong></td><td>Archive after final state</td></tr><tr><td><strong>Export selected</strong></td><td>CSV</td></tr></tbody></table><h2 id="csv-export" tabindex="-1"><a class="header-anchor" href="#csv-export"><span>CSV export</span></a></h2><p>Click <strong>Export → CSV</strong> at the top right. The export includes the buyer&#39;s reason, resolution, status, and all timestamps. Use it for:</p><ul><li>Legal escalations</li><li>Stripe / PayPal chargeback evidence</li><li>Internal CS handoff</li><li>Quarterly dispute-rate reporting</li></ul><p>For the full export endpoint, see <a href="/admin-tools.html" target="_blank" rel="noopener noreferrer">Tools</a>.</p><h2 id="sla-tracking" tabindex="-1"><a class="header-anchor" href="#sla-tracking"><span>SLA tracking</span></a></h2><p>The page shows a <strong>time-since-filed</strong> column. Configurable warning thresholds:</p><table><thead><tr><th>Threshold</th><th>Default</th></tr></thead><tbody><tr><td>Yellow warning</td><td>24 hours</td></tr><tr><td>Red warning</td><td>72 hours</td></tr></tbody></table><p>Bulk-filter by &quot;Open &gt; 72 hrs&quot; for SLA breach review.</p><h2 id="notifications" tabindex="-1"><a class="header-anchor" href="#notifications"><span>Notifications</span></a></h2><table><thead><tr><th>Trigger</th><th>Recipient</th><th>Email class</th></tr></thead><tbody><tr><td>Dispute filed</td><td>Admin (notification)</td><td>(system notice, no template)</td></tr><tr><td>Status → investigating</td><td>Buyer</td><td>(auto-reply)</td></tr><tr><td>Resolution set</td><td>Buyer</td><td>resolution email with note</td></tr></tbody></table><p>Customer-facing notifications can be branded via <a href="/admin-design-studio.html" target="_blank" rel="noopener noreferrer">Design Studio</a>.</p><h2 id="reporting" tabindex="-1"><a class="header-anchor" href="#reporting"><span>Reporting</span></a></h2><p><a href="/admin-reports.html" target="_blank" rel="noopener noreferrer">Reports → Disputes</a> shows:</p><ul><li>Dispute rate (disputes / completed orders)</li><li>Average resolution time</li><li>Top sellers by dispute count (potential fraud signal)</li><li>Top buyers by dispute count (potential fraud signal)</li><li>Common reason categories</li></ul><h2 id="common-workflows" tabindex="-1"><a class="header-anchor" href="#common-workflows"><span>Common workflows</span></a></h2><h3 id="triage-today-s-new-disputes" tabindex="-1"><a class="header-anchor" href="#triage-today-s-new-disputes"><span>&quot;Triage today&#39;s new disputes&quot;</span></a></h3><ol><li>Status filter → <strong>Open</strong></li><li>Sort by <strong>Created</strong> ascending</li><li>Open each → mark <strong>Investigating</strong> if action will take &gt;1 day, otherwise resolve immediately</li></ol><h3 id="close-out-the-sla-breached-backlog" tabindex="-1"><a class="header-anchor" href="#close-out-the-sla-breached-backlog"><span>&quot;Close out the SLA-breached backlog&quot;</span></a></h3><ol><li>Sort by <strong>Created</strong> ascending</li><li>Resolve each in turn</li><li>Bulk-close once status is <code>resolved</code></li></ol><h3 id="quarterly-dispute-report-for-management" tabindex="-1"><a class="header-anchor" href="#quarterly-dispute-report-for-management"><span>&quot;Quarterly dispute report for management&quot;</span></a></h3><ol><li>Date range → last quarter</li><li><strong>Export → CSV</strong></li><li>Pivot in your tool of choice</li></ol>',47)])])}]]),i=JSON.parse('{"path":"/admin-disputes.html","title":"Disputes","lang":"en-US","frontmatter":{},"headers":[{"level":2,"title":"What a dispute is","slug":"what-a-dispute-is","link":"#what-a-dispute-is","children":[]},{"level":2,"title":"How disputes are filed","slug":"how-disputes-are-filed","link":"#how-disputes-are-filed","children":[]},{"level":2,"title":"Page layout","slug":"page-layout","link":"#page-layout","children":[]},{"level":2,"title":"Status workflow","slug":"status-workflow","link":"#status-workflow","children":[]},{"level":2,"title":"Resolution actions","slug":"resolution-actions","link":"#resolution-actions","children":[]},{"level":2,"title":"Per-row drawer","slug":"per-row-drawer","link":"#per-row-drawer","children":[]},{"level":2,"title":"Bulk actions","slug":"bulk-actions","link":"#bulk-actions","children":[]},{"level":2,"title":"CSV export","slug":"csv-export","link":"#csv-export","children":[]},{"level":2,"title":"SLA tracking","slug":"sla-tracking","link":"#sla-tracking","children":[]},{"level":2,"title":"Notifications","slug":"notifications","link":"#notifications","children":[]},{"level":2,"title":"Reporting","slug":"reporting","link":"#reporting","children":[]},{"level":2,"title":"Common workflows","slug":"common-workflows","link":"#common-workflows","children":[{"level":3,"title":"\\"Triage today\'s new disputes\\"","slug":"triage-today-s-new-disputes","link":"#triage-today-s-new-disputes","children":[]},{"level":3,"title":"\\"Close out the SLA-breached backlog\\"","slug":"close-out-the-sla-breached-backlog","link":"#close-out-the-sla-breached-backlog","children":[]},{"level":3,"title":"\\"Quarterly dispute report for management\\"","slug":"quarterly-dispute-report-for-management","link":"#quarterly-dispute-report-for-management","children":[]}]}],"git":{},"filePathRelative":"admin-disputes.md"}')}}]);